import React, { useEffect, useState } from 'react';
import { PageHeader, Card, Table, Badge } from '../components/ui';
import { auditAPI } from '../services/api';

const actionColors = {
  'login': 'success',
  'logout': 'neutral',
  'create_user': 'info',
  'delete_user': 'danger',
  'approve_leave': 'primary',
  'reject_leave': 'warning'
};

export default function AuditLogs() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    auditAPI.list().then(res => {
      setLogs(res.data || []);
    }).catch(err => {
      console.error(err);
      setLogs([]);
    }).finally(() => {
      setLoading(false);
    });
  }, []);

  const cols = [
    { key: 'created_at', label: 'Timestamp', render: (r) => new Date(r.timestamp || r.created_at).toLocaleString() },
    { key: 'user_email', label: 'Actor', render: (r) => r.user_email || 'System' },
    { key: 'action', label: 'Action', render: (r) => (
      <Badge variant={actionColors[r.action] || 'neutral'}>{r.action.replace('_', ' ')}</Badge>
    )},
    { key: 'details', label: 'Details', render: (r) => r.details || '—' },
    { key: 'ip_address', label: 'IP Address', render: (r) => r.ip_address || '—' }
  ];

  return (
    <>
      <PageHeader
        title="Audit Logs"
        subtitle="System-wide action tracking and security events"
      />
      <Card style={{ padding: 0, overflow: 'hidden' }}>
        <Table cols={cols} rows={logs} loading={loading} emptyMsg="No audit logs available" />
      </Card>
    </>
  );
}
